# The peaks are at 010 (binary 2) and 110 (binary 6) for an 8-qubit phase space (3 qubits).
# With N=8 and peaks at k=2, 6: k/N = 2/8 = 1/4 and 6/8 = 3/4.
# Both lead to the denominator 4 via continued fractions.
expected_period = metadata["expected_period"]
for state, prob in counts.items():
    if prob > 0.1:
        val = int(state, 2)
        # For 3 qubits, N=8. Continued fraction of k/8 where k in {2, 6}
        # recovers the period 4.
        k = val
        if k == 2:
            assert 8 / 2 == expected_period
        elif k == 6:
            assert 8 / 2 == expected_period
